mapper.select:
/* TM_ECS_INTN_MENU_Dao_retrieveMenu */ SELECT A.MENU_ID, A.MENU_NM, A.MENU_SYS_DIV_CD, (SELECT DISTINCT CMMN_CD_NM FROM SCM.tc_sc_cd WHERE CLS_CD = 'SCM_0000' AND CMMN_CD = A.MENU_SYS_DIV_CD AND USE_YN = 'Y' ) AS MENU_SYS_DIV_NM, --시스템구분코드명 A.UPPER_MENU_ID, (SELECT DISTINCT MENU_NM FROM tm_ecs_intn_menu WHERE MENU_ID = A.UPPER_MENU_ID AND MENU_SYS_DIV_CD = A.MENU_SYS_DIV_CD AND USE_YN = 'Y' ) AS UPPER_MENU_NM, A.MENU_ORDR, A.SCRIN_ID, (SELECT DISTINCT SCRIN_NM FROM tm_ecs_intn_scrin WHERE SCRIN_ID = A.SCRIN_ID AND INTN_SYS_DIV_CD = A.MENU_SYS_DIV_CD AND USE_YN = 'Y' ) AS SCRIN_NM, A.MENU_LVL, A.MENU_DC, A.MENU_HIDE_YN, A.POPUP_YN, A.MENU_EXECUT_YN, A.USE_YN, A.MENU_APPLC_DE, A.MENU_END_DE, A.CALL_PARM, TO_CHAR(A.FRST_REGIST_DT, 'YYYY-MM-DD HH:MM:DD') AS FRST_REGIST_DT, A.FRST_RGSTR_ID, (SELECT DISTINCT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.FRST_RGSTR_ID) AS FRST_RGSTR_NM, TO_CHAR(A.LAST_UPDT_DT, 'YYYY-MM-DD HH:MM:DD') AS LAST_UPDT_DT, A.LAST_UPDUSR_ID, (SELECT DISTINCT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.LAST_UPDUSR_ID ) AS LAST_UPDUSR_NM FROM tm_ecs_intn_menu A WHERE A.MENU_SYS_DIV_CD = #{menuSysDivCd}
AND A.MENU_NM LIKE #{menuNm} || '%'
START WITH A.UPPER_MENU_ID IS NULL OR A.UPPER_MENU_ID = 'NULL' CONNECT BY PRIOR A.MENU_ID = A.UPPER_MENU_ID ORDER SIBLINGS BY A.MENU_SYS_DIV_CD, A.MENU_ORDR, A.MENU_LVL

mapper.delete:
/* TM_ECS_INTN_MENU_Dao_deleteMenuMng */
DELETE FROM
	tm_ecs_intn_menu 
WHERE
	MENU_ID = #{menuId}

mapper.select:
/* TM_ECS_INTN_MENU_Dao_retrieveIntnAthrMenu */ SELECT A.ATHR_ID, (SELECT ATHR_NM FROM tm_ecs_intn_athr WHERE A.ATHR_ID = ATHR_ID ) AS ATHR_NM, M.INTN_SYS_DIV_CD, M.MENU_ID, M.MENU_NM, M.MENU_DC, M.SCRIN_ID, M.SCRIN_NM, A.BTN_ATHR_LIST, DECODE(A.APPLC_STRT_DE, '', M.MENU_APPLC_DE, A.APPLC_STRT_DE) AS APPLC_STRT_DE, DECODE(A.APPLC_END_DE, '', M.MENU_END_DE, A.APPLC_END_DE) AS APPLC_END_DE FROM tm_ecs_intn_athr_menu A, (SELECT B.MENU_ID, B.MENU_NM, B.MENU_SYS_DIV_CD AS INTN_SYS_DIV_CD, B.MENU_DC, B.SCRIN_ID, (SELECT SCRIN_NM FROM tm_ecs_intn_scrin WHERE B.SCRIN_ID = SCRIN_ID ) AS SCRIN_NM, B.MENU_ORDR, B.MENU_APPLC_DE, B.MENU_END_DE FROM tm_ecs_intn_menu B WHERE TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN B.MENU_APPLC_DE AND B.MENU_END_DE AND B.MENU_EXECUT_YN = 'Y' ) M WHERE A.MENU_ID(+) = M.MENU_ID
/* 권한그룹 선택 후 권한별 메뉴목록에서 검색시 */ AND A.ATHR_ID(+) = #{athrId}
/* 시스템 구분 선택 시 */ AND (M.INTN_SYS_DIV_CD = #{intnSysDivCd} OR M.INTN_SYS_DIV_CD = 'ECS')
/* 메뉴명 검색 시 */ AND M.MENU_NM LIKE '%' || #{menuNm} || '%'
/* 메뉴명 검색 시 */ AND M.MENU_ID LIKE '%' || #{menuId} || '%'
ORDER BY M.MENU_ORDR

mapper.update:
/* TM_ECS_INTN_MENU_Dao_updateAthrMenu */
UPDATE
	tm_ecs_intn_athr_menu
SET
	BTN_ATHR_LIST = #{btnAthrList},
	APPLC_STRT_DE = #{applcStrtDe},
	APPLC_END_DE = #{applcEndDe},
	LAST_UPDT_DT = SYSDATE,
	LAST_UPDUSR_ID = #{lastUpdusrId}
WHERE
	ATHR_ID = #{athrId}
	AND MENU_ID = #{menuId}

mapper.delete:
/* TM_ECS_INTN_MENU_Dao_deleteAthrMenu */
DELETE FROM
	tm_ecs_intn_athr_menu
WHERE
	ATHR_ID = #{athrId}
	AND MENU_ID = #{menuId}
